SELECT al.access_date
FROM access_logs al
WHERE al.access_date = '2023-05-01' AND al.access_type = 'view';

SELECT RTRIM(country_name) AS country_name
FROM countries
ORDER BY country_name;

SELECT AVG(health_indicators.life_expectancy) AS average_life_expectancy
FROM health_indicators
WHERE health_indicators.year = (
    SELECT MAX(year)
    FROM health_indicators
);
